class SQLQueryValidator {
  private val dangerousPatterns = Seq(
    "(?i)\\b(DROP|DELETE|TRUNCATE|INSERT|UPDATE|CREATE|ALTER|GRANT|REVOKE)\\b".r,
    "(?i)\\bSET\\s+\\w+\\s*=".r,
    "(?i)\\bCALL\\b".r,
    "(?i)\\bEXEC(UTE)?\\b".r,
    "(?i);\\s*\\w+".r
  )

  private val maxQueryLength = 10000
  private val maxUnions = 5
  private val maxSubqueries = 10

  def validate(query: String): Either[String, String] = {
    if (query == null || query.trim.isEmpty) {
      return Left("Query cannot be empty")
    }

    if (query.length > maxQueryLength) {
      return Left(s"Query exceeds maximum length of $maxQueryLength characters")
    }

    for (pattern <- dangerousPatterns) {
      if (pattern.findFirstIn(query).isDefined) {
        return Left(s"Query contains forbidden operation: ${pattern.toString}")
      }
    }

    val unionCount = "(?i)\\bUNION\\b".r.findAllIn(query).length
    if (unionCount > maxUnions) {
      return Left(s"Query contains too many UNION operations (max: $maxUnions)")
    }

    val subqueryCount = "\\(".r.findAllIn(query).length
    if (subqueryCount > maxSubqueries) {
      return Left(s"Query appears to have too many subqueries (max: $maxSubqueries)")
    }

    Right(query.trim)
  }
}

class QueryExecutor(spark: SparkSession) {
  private val validator = new SQLQueryValidator()

  def executeQuery(request: QueryRequest): QueryResult = {
    val startTime = System.currentTimeMillis()

    validator.validate(request.query) match {
      case Left(error) =>
        QueryResult(
          queryId = request.queryId,
          success = false,
          executionTimeMs = System.currentTimeMillis() - startTime,
          error = Some(s"Validation failed: $error")
        )
      case Right(validQuery) =>
        executeValidatedQuery(request, validQuery, startTime)
    }
  }

  private def executeValidatedQuery(
    request: QueryRequest,
    validQuery: String,
    startTime: Long
  ): QueryResult = {
    Try {
      spark.sparkContext.setJobDescription(s"Query ${request.queryId} by user ${request.userId}")
      spark.sparkContext.setLocalProperty("spark.scheduler.pool", "fair")
      
      val df = spark.sql(validQuery)
      
      val limitedDf = df.limit(request.maxRows)
      
      val resultData = limitedDf.toJSON.collect().mkString("[", ",", "]")
      val rowCount = df.count()
      
      QueryResult(
        queryId = request.queryId,
        success = true,
        data = Some(resultData),
        rowCount = Some(rowCount),
        executionTimeMs = System.currentTimeMillis() - startTime
      )
    } match {
      case Success(result) => result
      case Failure(exception) =>
        val errorMessage = exception match {
          case pe: ParseException => s"SQL syntax error: ${pe.getMessage}"
          case ae: org.apache.spark.sql.AnalysisException => s"Analysis error: ${ae.getMessage}"
          case _ => s"Execution error: ${exception.getMessage}"
        }
        
        QueryResult(
          queryId = request.queryId,
          success = false,
          executionTimeMs = System.currentTimeMillis() - startTime,
          error = Some(errorMessage)
        )
    }
  }

  def explainQuery(query: String): Either[String, String] = {
    validator.validate(query) match {
      case Left(error) => Left(error)
      case Right(validQuery) =>
        Try {
          val df = spark.sql(validQuery)
          val plan = df.queryExecution.toString()
          plan
        } match {
          case Success(plan) => Right(plan)
          case Failure(exception) => Left(s"Failed to explain query: ${exception.getMessage}")
        }
    }
  }
}

class DataLakeManager(spark: SparkSession) {
  def registerTables(dataLakePath: String): Unit = {
    val tables = Map(
      "users" -> s"$dataLakePath/users",
      "transactions" -> s"$dataLakePath/transactions",
      "products" -> s"$dataLakePath/products",
      "events" -> s"$dataLakePath/events",
      "sessions" -> s"$dataLakePath/sessions"
    )

    tables.foreach { case (tableName, path) =>
      Try {
        val df = spark.read.parquet(path)
        df.createOrReplaceTempView(tableName)
        println(s"Registered table: $tableName from $path")
      } match {
        case Success(_) => 
        case Failure(e) => println(s"Warning: Could not register table $tableName: ${e.getMessage}")
      }
    }
  }

  def refreshTable(tableName: String, path: String): Try[Unit] = {
    Try {
      val df = spark.read.parquet(path)
      df.createOrReplaceTempView(tableName)
    }
  }

  def listAvailableTables(): Seq[String] = {
    spark.catalog.listTables().collect().map(_.name).toSeq
  }

  def getTableSchema(tableName: String): Option[String] = {
    Try {
      spark.catalog.listColumns(tableName).collect()
        .map(col => s"${col.name}: ${col.dataType}")
        .mkString(", ")
    }.toOption
  }
}

class QueryAuditLogger {
  def logQuery(request: QueryRequest, result: QueryResult): Unit = {
    val logEntry = Map(
      "timestamp" -> System.currentTimeMillis(),
      "queryId" -> request.queryId,
      "userId" -> request.userId,
      "query" -> request.query,
      "success" -> result.success,
      "executionTimeMs" -> result.executionTimeMs,
      "rowCount" -> result.rowCount.getOrElse(0),
      "error" -> result.error.getOrElse("")
    )
    
    println(s"AUDIT: ${logEntry.map { case (k, v) => s"$k=$v" }.mkString(", ")}")
  }
}

class BigDataAnalyticsPlatform(spark: SparkSession, dataLakePath: String) {
  private val dataLakeManager = new DataLakeManager(spark)
  private val queryExecutor = new QueryExecutor(spark)
  private val auditLogger = new QueryAuditLogger()

  def initialize(): Unit = {
    configureSpark()
    dataLakeManager.registerTables(dataLakePath)
  }

  private def configureSpark(): Unit = {
    spark.conf.set("spark.sql.adaptive.enabled", "true")
    spark.conf.set("spark.sql.adaptive.coalescePartitions.enabled", "true")
    spark.conf.set("spark.sql.autoBroadcastJoinThreshold", "10485760")
    spark.conf.set("spark.sql.shuffle.partitions", "200")
  }

  def processQuery(request: QueryRequest): QueryResult = {
    val result = queryExecutor.executeQuery(request)
    auditLogger.logQuery(request, result)
    result
  }

  def explainQuery(query: String): Either[String, String] = {
    queryExecutor.explainQuery(query)
  }

  def listTables(): Seq[String] = {
    dataLakeManager.listAvailableTables()
  }

  def getTableSchema(tableName: String): Option[String] = {
    dataLakeManager.getTableSchema(tableName)
  }

  def refreshTable(tableName: String, path: String): Boolean = {
    dataLakeManager.refreshTable(tableName, path).isSuccess
  }
}

